const RUBLE_EXCHANGE_RATE = 79;
const billing_polza = Number($json.billing_polza) - Number($json.amount);
const billing_neuro = -(Number($json.billing_neuro) - Number($json.total_usage)) / 100;
const startedAtMs = DateTime.fromISO($json.created_at);
const diff = startedAtMs.diffNow().negate().toFormat("hh':'mm':'ss");
const done = Number($json.chunks_done);
const total = Number($json.chunks_total);
const ratio = Math.min(1, Math.max(0, done / total));
const startedAt = startedAtMs.toFormat("dd.MM.yyyy HH:mm:ss");
const width = 20;
const filled = Math.round(ratio * width);
const bar = '█'.repeat(filled) + '░'.repeat(width - filled);

return {
  message: `\n🔄 <b>Перевод в процессе</b>\n\n📄 Документ: ${$json.file_name}\n<b>🗓 Старт:</b> <code>${ startedAt }</code>\n<b>⏱ Прошло: <code>${ diff }</code></b>\n<b>📊 Прогресс:</b> <code>${bar} ${Math.floor(ratio*100)}%</code>\n<b>🧩 Текущий чанк: <code>${done}/${total}</code></b>\n💰 Потрачено на Polza.ai: ₽${billing_polza.toFixed(2)}\n💰 Потрачено на NeuroAPI: ₽${(billing_neuro * RUBLE_EXCHANGE_RATE).toFixed(2).toString().replace(/\B(?=(\d{3})+(?!\d))/g, " ")}\n\n<i>Сообщение сгенерировано автоматически.</i>`,
  type: 'process',
  button: {}
};
